def string_compress(s):
    if len(s) <= 1: return s
    compressed, i, count = '', 1, 1
    for j in range(1, len(s)):
        if s[j] == s[j-1]: 
            count += 1
        else: 
            compressed += s[j-1] + str(count)
            count = 1
    compressed += s[-1] + str(count)
    return compressed if len(compressed) < len(s) else s
